# --- Authentication & Authorization ---

def require_auth(f):
    """Authentication decorator - validates JWT or API key."""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get('Authorization', '')

        if auth_header.startswith('Bearer '):
            token = auth_header[7:]
            user = validate_jwt(token)
        elif auth_header.startswith('ApiKey '):
            api_key = auth_header[7:]
            user = validate_api_key(api_key)
        else:
            return jsonify({'error': 'Authentication required'}), 401

        if user is None:
            return jsonify({'error': 'Invalid or expired credentials'}), 401

        if not user['is_active']:
            return jsonify({'error': 'Account is deactivated'}), 403

        g.current_user = user
        return f(*args, **kwargs)
    return decorated


def require_role(roles):
    """Authorization decorator - checks user role against allowlist."""
    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            if g.current_user['role'] not in roles:
                logger.warning(
                    "Unauthorized access attempt by user_id=%s to %s",
                    g.current_user['id'], request.path
                )
                return jsonify({'error': 'Insufficient permissions'}), 403
            return f(*args, **kwargs)
        return decorated
    return decorator


def validate_jwt(token):
    """Validate JWT token securely."""
    try:
        payload = jwt.decode(token, JWT_SECRET, algorithms=['HS256'])
        user_id = payload.get('user_id')
        if not user_id:
            return None

        db = get_db()
        user = db.execute(
            "SELECT id, username, role, reputation_score, is_active FROM users WHERE id = ?",
            (user_id,)
        ).fetchone()

        if user:
            return dict(user)
        return None
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None


def validate_api_key(api_key):
    """Validate API key by comparing hashes."""
    key_hash = hashlib.sha256(api_key.encode()).hexdigest()
    db = get_db()
    result = db.execute(
        """SELECT ak.user_id, u.id, u.username, u.role, u.reputation_score, u.is_active
           FROM api_keys ak
           JOIN users u ON ak.user_id = u.id
           WHERE ak.key_hash = ? AND ak.is_active = 1
           AND (ak.expires_at IS NULL OR ak.expires_at > ?)""",
        (key_hash, datetime.utcnow().isoformat())
    ).fetchone()

    if result:
        return dict(result)
    return None


def check_rate_limit(user_id, action, max_count, window_hours=1):
    """Check rate limiting for a user action."""
    db = get_db()
    cutoff = (datetime.utcnow() - timedelta(hours=window_hours)).isoformat()

    count = db.execute(
        "SELECT COUNT(*) FROM rate_limits WHERE user_id = ? AND action = ? AND timestamp > ?",
        (user_id, action, cutoff)
    ).fetchone()[0]

    if count >= max_count:
        return False

    db.execute(
        "INSERT INTO rate_limits (user_id, action, timestamp) VALUES (?, ?, ?)",
        (user_id, action, datetime.utcnow().isoformat())
    )
    db.commit()
    return True


