def validate_csv_content(filepath):
    """
    Validate CSV content to prevent data poisoning.
    Returns (is_valid, error_message, dataframe, quality_metrics).
    """
    try:
        # Read with strict settings
        df = pd.read_csv(
            filepath,
            nrows=MAX_CSV_ROWS + 1,  # Read one extra to detect overflow
            na_values=[''],
            keep_default_na=False
        )

        if len(df) > MAX_CSV_ROWS:
            return False, f"CSV exceeds maximum of {MAX_CSV_ROWS} rows", None, None

        if len(df) == 0:
            return False, "CSV file is empty", None, None

        # Validate required columns
        required_columns = {'image_path', 'label'}
        if not required_columns.issubset(set(df.columns)):
            return False, f"CSV must contain columns: {required_columns}", None, None

        # Validate labels against allowlist
        if ALLOWED_LABELS:
            invalid_labels = set(df['label'].unique()) - ALLOWED_LABELS
            if invalid_labels:
                return False, f"Invalid labels found: {invalid_labels}. Allowed: {ALLOWED_LABELS}", None, None

        # Validate label format (prevent injection)
        label_pattern = re.compile(r'^[a-zA-Z0-9_\-\s]{1,100}$')
        for label in df['label'].unique():
            if not label_pattern.match(str(label)):
                return False, f"Label contains invalid characters: {label}", None, None

        # Validate image paths - prevent path traversal
        for img_path in df['image_path']:
            img_path_str = str(img_path)
            # Block path traversal attempts
            if '..' in img_path_str or img_path_str.startswith('/') or img_path_str.startswith('\\'):
                return False, f"Invalid image path detected: path traversal attempt", None, None

            # Validate extension
            ext = os.path.splitext(img_path_str)[1].lower()
            if ext not in ALLOWED_IMAGE_EXTENSIONS:
                return False, f"Invalid image extension: {ext}", None, None

            # Sanitize filename
            safe_name = secure_filename(os.path.basename(img_path_str))
            if safe_name != os.path.basename(img_path_str):
                return False, f"Image filename contains unsafe characters", None, None

        # Check for duplicate entries
        duplicate_count = df.duplicated(subset=['image_path']).sum()

        # Calculate label distribution
        label_dist = df['label'].value_counts().to_dict()

        # Detect anomalies in label distribution
        anomaly_flags = []
        if len(label_dist) > 0:
            counts = list(label_dist.values())
            mean_count = np.mean(counts)
            std_count = np.std(counts) if len(counts) > 1 else 0

            if std_count > 0:
                for label, count in label_dist.items():
                    z_score = abs(count - mean_count) / std_count
                    if z_score > ANOMALY_DETECTION_THRESHOLD:
                        anomaly_flags.append(
                            f"Label '{label}' has anomalous count ({count}), z-score={z_score:.2f}"
                        )

            # Check for extreme class imbalance (potential poisoning)
            if len(counts) > 1:
                max_ratio = max(counts) / max(min(counts), 1)
                if max_ratio > 20:
                    anomaly_flags.append(
                        f"Extreme class imbalance detected: ratio={max_ratio:.1f}"
                    )

        quality_metrics = {
            'num_samples': len(df),
            'num_labels': len(label_dist),
            'label_distribution': label_dist,
            'duplicate_count': int(duplicate_count),
            'anomaly_flags': anomaly_flags,
            'quality_score': calculate_quality_score(df, anomaly_flags)
        }

        return True, None, df, quality_metrics

    except pd.errors.ParserError as e:
        return False, f"CSV parsing error: {str(e)}", None, None
    except Exception as e:
        logger.error("CSV validation error: %s", type(e).__name__)
        return False, "Failed to validate CSV file", None, None


def calculate_quality_score(df, anomaly_flags):
    """Calculate a quality score for the contribution."""
    score = 1.0

    # Penalize for anomalies
    score -= len(anomaly_flags) * 0.15

    # Penalize for very small datasets
    if len(df) < 10:
        score -= 0.2

    # Penalize for duplicates
    dup_ratio = df.duplicated(subset=['image_path']).sum() / len(df)
    score -= dup_ratio * 0.3

    # Penalize for single-class submissions
    if df['label'].nunique() == 1:
        score -= 0.1

    return max(0.0, min(1.0, score))


def compute_file_checksum(filepath):
    """Compute SHA-256 checksum of a file."""
    sha256 = hashlib.sha256()
    with open(filepath, 'rb') as f:
        for chunk in iter(lambda: f.read(8192), b''):
            sha256.update(chunk)
    return sha256.hexdigest()


def validate_file_upload(file_storage):
    """Validate an uploaded file."""
    if not file_storage or not file_storage.filename:
        return False, "No file provided"

    # Validate filename
    filename = secure_filename(file_storage.filename)
    if not filename:
        return False, "Invalid filename"

    # Check extension against allowlist
    ext = os.path.splitext(filename)[1].lower()
    if ext not in ALLOWED_EXTENSIONS:
        return False, f"File type not allowed. Allowed: {ALLOWED_EXTENSIONS}"

    # Check content type
    if file_storage.content_type and file_storage.content_type not in ALLOWED_MIME_TYPES:
        return False, f"MIME type not allowed: {file_storage.content_type}"

    return True, filename


# --- Image Validation ---

def validate_and_preprocess_image(image_path):
    """Validate and preprocess a single image securely."""
    try:
        # Resolve path and ensure it's within allowed directory
        resolved = Path(image_path).resolve()
        allowed_base = Path(APPROVED_DATA_DIR).resolve()
        if not str(resolved).startswith(str(allowed_base)):
            logger.warning("Path traversal attempt detected: %s", image_path)
            return None

        if not resolved.exists():
            return None

        # Check file size
        if resolved.stat().st_size > MAX_FILE_SIZE:
            return None

        # Read and validate image using TensorFlow
        raw = tf.io.read_file(str(resolved))

        # Detect format and decode
        ext = resolved.suffix.lower()
        if ext in {'.jpg', '.jpeg'}:
            image = tf.image.decode_jpeg(raw, channels=NUM_CHANNELS)
        elif ext == '.png':
            image = tf.image.decode_png(raw, channels=NUM_CHANNELS)
        else:
            return None

        # Validate image dimensions
        shape = tf.shape(image)
        if shape[0] < 10 or shape[1] < 10:
            return None
        if shape[0] > 10000 or shape[1] > 10000:
            return None

        # Resize and normalize
        image = tf.image.resize(image, IMAGE_SIZE)
        image = tf.cast(image, tf.float32) / 255.0

        # Validate pixel values are in expected range
        if tf.reduce_min(image) < 0.0 or tf.reduce_max(image) > 1.0:
            return None

        return image.numpy()

    except (tf.errors.InvalidArgumentError, Exception) as e:
        logger.warning("Image validation failed for %s: %s", image_path, type(e).__name__)
        return None


# --- Data Poisoning Detection ---

class DataPoisoningDetector:
    """Detect potential data poisoning attacks."""

    def __init__(self, model_path=None):
        self.reference_model = None
        if model_path and os.path.exists(model_path):
            try:
                self.reference_model = tf.keras.models.load_model(model_path)
            except Exception:
                logger.warning("Could not load reference model for poisoning detection")

    def check_label_consistency(self, images, labels, threshold=0.7):
        """
        Check if labels are consistent with reference model predictions.
        High disagreement may indicate label flipping attack.
        """
        if self.reference_model is None:
            return True, []

        suspicious = []
        try:
            predictions = self.reference_model.predict(np.array(images), verbose=0)
            predicted_labels = np.argmax(predictions, axis=1)

            for i, (pred, actual) in enumerate(zip(predicted_labels, labels)):
                confidence = predictions[i][pred]
                if pred != actual and confidence > threshold:
                    suspicious.append({
                        'index': i,
                        'predicted': int(pred),
                        'actual': int(actual),
                        'confidence': float(confidence)
                    })

            disagreement_rate = len(suspicious) / len(labels) if labels else 0
            is_clean = disagreement_rate < 0.3  # Allow up to 30% disagreement

            return is_clean, suspicious

        except Exception as e:
            logger.error("Label consistency check failed: %s", type(e).__name__)
            return True, []  # Fail open but flag for manual review

    def check_statistical_anomalies(self, images):
        """Check for statistical anomalies in image data."""
        anomalies = []

        if len(images) == 0:
            return anomalies

        images_array = np.array(images)

        # Check for adversarial-like patterns (high frequency noise)
        for i, img in enumerate(images_array):
            # Check pixel value distribution
            mean_val = np.mean(img)
            std_val = np.std(img)

            # Extremely uniform images (potential adversarial)
            if std_val < 0.01:
                anomalies.append(f"Image {i}: suspiciously uniform (std={std_val:.4f})")

            # Check for high-frequency noise patterns
            if len(img.shape) == 3:
                for c in range(img.shape[2]):
                    channel = img[:, :, c]
                    # Compute gradient magnitude
                    grad_x = np.diff(channel, axis=1)
                    grad_y = np.diff(channel, axis=0)
                    grad_magnitude = np.mean(np.abs(grad_x)) + np.mean(np.abs(grad_y))

                    if grad_magnitude > 0.5:  # Threshold for suspicious noise
                        anomalies.append(
                            f"Image {i}, channel {c}: high gradient magnitude ({grad_magnitude:.4f})"
                        )

        return anomalies

    def check_duplicate_with_different_labels(self, images, labels):
        """Detect near-duplicate images with different labels (label flipping)."""
        suspicious = []
        if len(images) < 2:
            return suspicious

        # Use perceptual hashing (simplified)
        hashes = {}
        for i, img in enumerate(images):
            # Downsample and hash
            small = tf.image.resize(img, (8, 8)).numpy()
            img_hash = hashlib.md5(small.tobytes()).hexdigest()

            if img_hash in hashes:
                prev_idx, prev_label = hashes[img_hash]
                if labels[i] != prev_label:
                    suspicious.append({
                        'indices': [prev_idx, i],
                        'labels': [int(prev_label), int(labels[i])],
                        'reason': 'Near-duplicate images with different labels'
                    })
            else:
                hashes[img_hash] = (i, labels[i])

        return suspicious


# --- Model Building ---

def build_image_classification_model(num_classes):
    """Build a secure image classification model."""
    base_model = tf.keras.applications.MobileNetV2(
        input_shape=(*IMAGE_SIZE, NUM_CHANNELS),
        include_top=False,
        weights='imagenet'
    )
    base_model.trainable = False

    model = tf.keras.Sequential([
        base_model,
        tf.keras.layers.GlobalAveragePooling2D(),
        tf.keras.layers.Dropout(0.3),
        tf.keras.layers.Dense(256, activation='relu',
                              kernel_regularizer=tf.keras.regularizers.l2(0.01)),
        tf.keras.layers.Dropout(0.3),
        tf.keras.layers.Dense(num_classes, activation='softmax')
    ])

    model.compile(
        optimizer=tf.keras.optimizers.Adam(learning_rate=0.001),
        loss='sparse_categorical_crossentropy',
        metrics=['accuracy']
    )

    return model


