@app.route('/api/auth/login', methods=['POST'])
def login():
    """Authenticate user and return JWT token."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Invalid request'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')

    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400

    # Validate username format
    if not re.match(r'^[a-zA-Z0-9_]{3,50}$', username):
        return jsonify({'error': 'Invalid credentials'}), 401

    db = get_db()
    user = db.execute(
        "SELECT id, username, password_hash, role, is_active FROM users WHERE username = ?",
        (username,)
    ).fetchone()

    if not user or not check_password_hash(user['password_hash'], password):
        # Use constant-time comparison via check_password_hash
        return jsonify({'error': 'Invalid credentials'}), 401

    if not user['is_active']:
        return jsonify({'error': 'Account is deactivated'}), 403

    # Update last login
    db.execute(
        "UPDATE users SET last_login = ? WHERE id = ?",
        (datetime.utcnow().isoformat(), user['id'])
    )
    db.commit()

    # Generate JWT
    token = jwt.encode({
        'user_id': user['id'],
        'role': user['role'],
        'exp': datetime.utcnow() + timedelta(hours=8),
        'iat': datetime.utcnow(),
        'jti': str(uuid.uuid4())
    }, JWT_SECRET, algorithm='HS256')

    logger.info("User logged in: user_id=%s", user['id'])

    return jsonify({
        'token': token,
        'expires_in': 8 * 3600,
        'user': {
            'id': user['id'],
            'username': user['username'],
            'role': user['role']
        }
    })


@app.route('/api/auth/register', methods=['POST'])
def register():
    """Register a new contributor account."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Invalid request'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')

    # Validate username
    if not re.match(r'^[a-zA-Z0-9_]{3,50}$', username):
        return jsonify({'error': 'Username must be 3-50 alphanumeric characters or underscores'}), 400

    # Validate password strength
    if len(password) < 12:
        return jsonify({'error': 'Password must be at least 12 characters'}), 400
    if not re.search(r'[A-Z]', password):
        return jsonify({'error': 'Password must contain uppercase letter'}), 400
    if not re.search(r'[a-z]', password):
        return jsonify({'error': 'Password must contain lowercase letter'}), 400
    if not re.search(r'[0-9]', password):
        return jsonify({'error': 'Password must contain digit'}), 400

    db = get_db()

    # Check if username exists
    existing = db.execute(
        "SELECT id FROM users WHERE username = ?", (username,)
    ).fetchone()
    if existing:
        return jsonify({'error': 'Username already taken'}), 409

    user_id = str(uuid.uuid4())
    password_hash = generate_password_hash(password, method='pbkdf2:sha256:600000')

    db.execute(
        "INSERT INTO users (id, username, password_hash, role, reputation_score, is_active, created_at) VALUES (?, ?, ?, ?, ?, ?, ?)",
        (user_id, username, password_hash, 'contributor', 0.5, 1, datetime.utcnow().isoformat())
    )
    db.commit()

    logger.info("New user registered: user_id=%s", user_id)

    return jsonify({
        'message': 'Registration successful',
        'user_id': user_id
    }), 201


