@require_auth
def contribute_data():
    """Upload training data contribution."""
    user = g.current_user

    # Rate limiting
    if not check_rate_limit(user['id'], 'contribute', MAX_CONTRIBUTIONS_PER_HOUR):
        return jsonify({'error': 'Rate limit exceeded. Try again later.'}), 429

    # Check reputation
    if user.get('reputation_score', 0) < MIN_CONTRIBUTOR_REPUTATION:
        return jsonify({
            'error': 'Insufficient reputation score. Your contributions need more approvals.'
        }), 403

    # Validate file upload
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400

    file = request.files['file']
    is_valid, result = validate_file_upload(file)
    if not is_valid:
        return jsonify({'error': result}), 400

    filename = result

    # Save to temporary location first
    contribution_id = str(uuid.uuid4())
    temp_dir = tempfile.mkdtemp(prefix='ml_upload_')

    try:
        temp_path = os.path.join(temp_dir, filename)
        file.save(temp_path)

        # Compute checksum
        checksum = compute_file_checksum(temp_path)

        # Check for duplicate submissions
        db = get_db()
        existing = db.execute(
            "SELECT id FROM contributions WHERE file_checksum = ? AND status != 'rejected'",
            (checksum,)
        ).fetchone()
        if existing:
            return jsonify({'error': 'This file has already been submitted'}), 409

        # Validate CSV content
        is_valid, error, df, quality_metrics = validate_csv_content(temp_path)
        if not is_valid:
            return jsonify({'error': error}), 400

        # Move to upload directory with hashed name
        filename_hash = hashlib.sha256(
            f"{contribution_id}_{filename}".encode()
        ).hexdigest()
        os.makedirs(UPLOAD_DIR, exist_ok=True)
        dest_path = os.path.join(UPLOAD_DIR, f"{filename_hash}.csv")
        os.rename(temp_path, dest_path)

        # Set restrictive permissions
        os.chmod(dest_path, 0o640)

        # Determine initial status based on quality
        status = 'pending'
        if quality_metrics['quality_score'] < 0.3:
            status = 'flagged'
        if quality_metrics['anomaly_flags']:
            status = 'flagged'

        # Store contribution record
        db.execute(
            """INSERT INTO contributions
               (id, user_id, filename_hash, original_filename, file_checksum,
                status, num_samples, label_distribution, quality_score,
                anomaly_flags, submitted_at)
               VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)""",
            (
                contribution_id,
                user['id'],
                filename_hash,
                filename,
                checksum,
                status,
                quality_metrics['num_samples'],
                json.dumps(quality_metrics['label_distribution']),
                quality_metrics['quality_score'],
                json.dumps(quality_metrics['anomaly_flags']),
                datetime.utcnow().isoformat()
            )
        )
        db.commit()

        logger.info(
            "Contribution submitted: id=%s, user=%s, status=%s, quality=%.2f",
            contribution_id, user['id'], status, quality_metrics['quality_score']
        )

        return jsonify({
            'contribution_id': contribution_id,
            'status': status,
            'quality_metrics': {
                'num_samples': quality_metrics['num_samples'],
                'num_labels': quality_metrics['num_labels'],
                'quality_score': quality_metrics['quality_score'],
                'anomaly_flags': quality_metrics['anomaly_flags']
            },
            'message': 'Contribution submitted for review' if status == 'pending'
                       else 'Contribution flagged for manual review due to quality concerns'
        }), 201

    except Exception as e:
        logger.error("Contribution upload failed: %s", type(e).__name__)
        return jsonify({'error': 'Upload failed'}), 500
    finally:
        # Clean up temp directory
        import shutil
        if os.path.exists(temp_dir):
            shutil.rmtree(temp_dir, ignore_errors=True)


@app.route('/api/contributions/<contribution_id>/review', methods=['POST'])
@require_auth
@require_role(['admin', 'reviewer'])
def review_contribution(contribution_id):
    """Review a contribution (approve/reject)."""
    # Validate contribution_id format
    try:
        uuid.UUID(contribution_id)
    except ValueError:
        return jsonify({'error': 'Invalid contribution ID'}), 400

    data = request.get_json()
    if not data:
        return jsonify({'error': 'Invalid request'}), 400

    decision = data.get('decision', '').strip().lower()
    notes = data.get('notes', '').strip()[:500]  # Limit notes length

    if decision not in ('approve', 'reject'):
        return jsonify({'error': 'Decision must be "approve" or "reject"'}), 400

    db = get_db()
    user = g.current_user

    # Get contribution
    contribution = db.execute(
        "SELECT * FROM contributions WHERE id = ?",
        (contribution_id,)
    ).fetchone()

    if not contribution:
        return jsonify({'error': 'Contribution not found'}), 404

    # Prevent self-review
    if contribution['user_id'] == user['id']:
        return jsonify({'error': 'Cannot review your own contribution'}), 403

    # Check if already reviewed by this user
    existing_review = db.execute(
        "SELECT id FROM contribution_reviews WHERE contribution_id = ? AND reviewer_id = ?",
        (contribution_id, user['id'])
    ).fetchone()
    if existing_review:
        return jsonify({'error': 'You have already reviewed this contribution'}), 409

    review_id = str(uuid.uuid4())
    now = datetime.utcnow().isoformat()

    # Record the review
    db.execute(
        """INSERT INTO contribution_reviews (id, contribution_id, reviewer_id, decision, notes, reviewed_at)
           VALUES (?, ?, ?, ?, ?, ?)""",
        (review_id, contribution_id, user['id'], decision, notes, now)
    )

    # Count approvals and rejections
    reviews = db.execute(
        "SELECT decision, COUNT(*) as count FROM contribution_reviews WHERE contribution_id = ? GROUP BY decision",
        (contribution_id,)
    ).fetchall()

    review_counts = {r['decision']: r['count'] for r in reviews}
    approvals = review_counts.get('approve', 0)
    rejections = review_counts.get('reject', 0)

    # Update contribution status based on review consensus
    new_status = contribution['status']
    if rejections >= 2:
        new_status = 'rejected'
        # Decrease contributor reputation
        db.execute(
            "UPDATE users SET reputation_score = MAX(0, reputation_score - 0.05) WHERE id = ?",
            (contribution['user_id'],)
        )
    elif approvals >= MIN_APPROVALS_FOR_TRAINING:
        new_status = 'approved'
        # Increase contributor reputation
        db.execute(
            "UPDATE users SET reputation_score = MIN(1.0, reputation_score + 0.02) WHERE id = ?",
            (contribution['user_id'],)
        )

    if new_status != contribution['status']:
        rejection_reason = notes if new_status == 'rejected' else None
        db.execute(
            """UPDATE contributions SET status = ?, reviewed_at = ?, reviewed_by = ?, rejection_reason = ?
               WHERE id = ?""",
            (new_status, now, user['id'], rejection_reason, contribution_id)
        )

    db.commit()

    logger.info(
        "Contribution reviewed: id=%s, reviewer=%s, decision=%s, new_status=%s",
        contribution_id, user['id'], decision, new_status
    )

    return jsonify({
        'review_id': review_id,
        'contribution_status': new_status,
        'approvals': approvals,
        'rejections': rejections,
        'required_approvals': MIN_APPROVALS_FOR_TRAINING
    })


@app.route('/api/train', methods=['POST'])
@require_auth
@require_role(['admin'])
def trigger_training():
    """Trigger model training with approved contributions only."""
    user = g.current_user
    db = get_db()

    # Get all approved contributions
    contributions = db.execute(
        """SELECT * FROM contributions
           WHERE status = 'approved'
           ORDER BY submitted_at ASC"""
    ).fetchall()

    if not contributions:
        return jsonify({'error': 'No approved contributions available for training'}), 400

    training_run_id = str(uuid.uuid4())
    model_version = f"v_{datetime.utcnow().strftime('%Y%m%d_%H%M%S')}"
    contribution_ids = [c['id'] for c in contributions]

    # Record training run
    db.execute(
        """INSERT INTO training_runs (id, model_version, started_at, status, contribution_ids, initiated_by)
           VALUES (?, ?, ?, ?, ?, ?)""",
        (training_run_id, model_version, datetime.utcnow().isoformat(),
         'running', json.dumps(contribution_ids), user['id'])
    )
    db.commit()

    try:
        # Load and validate all approved data
        all_images = []
        all_labels = []
        label_to_idx = {}

        # Load allowed labels for index mapping
        if ALLOWED_LABELS:
            label_to_idx = {label: idx for idx, label in enumerate(sorted(ALLOWED_LABELS))}

        poisoning_detector = DataPoisoningDetector(
            model_path=os.path.join(MODEL_DIR, 'latest', 'model.keras')
        )

        os.makedirs(APPROVED_DATA_DIR, exist_ok=True)

        for contribution in contributions:
            csv_path = os.path.join(UPLOAD_DIR, f"{contribution['filename_hash']}.csv")
            if not os.path.exists(csv_path):
                logger.warning("CSV file missing for contribution %s", contribution['id'])
                continue

            df = pd.read_csv(csv_path, nrows=MAX_CSV_ROWS)

            for _, row in df.iterrows():
                label_str = str(row['label']).strip()
                if label_str not in label_to_idx:
                    continue

                # Construct safe image path within approved data directory
                safe_filename = secure_filename(os.path.basename(str(row['image_path'])))
                image_path = os.path.join(APPROVED_DATA_DIR, safe_filename)

                image = validate_and_preprocess_image(image_path)
                if image is not None:
                    all_images.append(image)
                    all_labels.append(label_to_idx[label_str])

        if len(all_images) < 10:
            db.execute(
                "UPDATE training_runs SET status = 'failed', completed_at = ? WHERE id = ?",
                (datetime.utcnow().isoformat(), training_run_id)
            )
            db.commit()
            return jsonify({'error': 'Insufficient valid training data'}), 400

        images_array = np.array(all_images)
        labels_array = np.array(all_labels)

        # Run poisoning detection
        is_clean, suspicious = poisoning_detector.check_label_consistency(
            all_images, all_labels
        )
        if not is_clean:
            logger.warning(
                "Potential data poisoning detected in training run %s: %d suspicious samples",
                training_run_id, len(suspicious)
            )
            # Remove suspicious samples
            suspicious_indices = {s['index'] for s in suspicious}
            clean_mask = [i not in suspicious_indices for i in range(len(all_images))]
            images_array = images_array[clean_mask]
            labels_array = labels_array[clean_mask]

        # Check for statistical anomalies
        stat_anomalies = poisoning_detector.check_statistical_anomalies(all_images)
        if stat_anomalies:
            logger.warning(
                "Statistical anomalies in training data: %s", stat_anomalies[:5]
            )

        # Check for duplicate images with different labels
        dup_anomalies = poisoning_detector.check_duplicate_with_different_labels(
            all_images, all_labels
        )
        if dup_anomalies:
            logger.warning(
                "Duplicate images with different labels detected: %d cases",
                len(dup_anomalies)
            )

        num_classes = len(label_to_idx)

        # Shuffle data
        indices = np.random.permutation(len(images_array))
        images_array = images_array[indices]
        labels_array = labels_array[indices]

        # Split into train/validation
        split_idx = int(0.8 * len(images_array))
        train_images = images_array[:split_idx]
        train_labels = labels_array[:split_idx]
        val_images = images_array[split_idx:]
        val_labels = labels_array[split_idx:]

        # Build and train model
        model = build_image_classification_model(num_classes)

        # Use callbacks for training stability
        callbacks = [
            tf.keras.callbacks.EarlyStopping(
                monitor='val_loss', patience=5, restore_best_weights=True
            ),
            tf.keras.callbacks.ReduceLROnPlateau(
                monitor='val_loss', factor=0.5, patience=3
            )
        ]

        history = model.fit(
            train_images, train_labels,
            validation_data=(val_images, val_labels),
            epochs=50,
            batch_size=32,
            callbacks=callbacks,
            verbose=0
        )

        # Evaluate
        val_loss, val_accuracy = model.evaluate(val_images, val_labels, verbose=0)

        # Save model
        model_save_path = os.path.join(MODEL_DIR, model_version)
        os.makedirs(model_save_path, exist_ok=True)
        model.save(os.path.join(model_save_path, 'model.keras'))

        # Save label mapping
        with open(os.path.join(model_save_path, 'label_mapping.json'), 'w') as f:
            json.dump(label_to_idx, f)

        # Update latest symlink
        latest_path = os.path.join(MODEL_DIR, 'latest')
        if os.path.islink(latest_path):
            os.unlink(latest_path)
        os.symlink(model_save_path, latest_path)

        metrics = {
            'val_loss': float(val_loss),
            'val_accuracy': float(val_accuracy),
            'train_samples': len(train_images),
            'val_samples': len(val_images),
            'num_classes': num_classes,
            'epochs_trained': len(history.history['loss']),
            'suspicious_samples_removed': len(suspicious) if not is_clean else 0,
            'statistical_anomalies': len(stat_anomalies),
            'duplicate_anomalies': len(dup_anomalies)
        }

        # Update training run record
        db.execute(
            """UPDATE training_runs SET status = 'completed', completed_at = ?, metrics = ?
               WHERE id = ?""",
            (datetime.utcnow().isoformat(), json.dumps(metrics), training_run_id)
        )

        # Mark contributions as used in training
        for cid in contribution_ids:
            db.execute(
                "UPDATE contributions SET status = 'trained' WHERE id = ?",
                (cid,)
            )

        db.commit()

        logger.info(
            "Training completed: run=%s, version=%s, accuracy=%.4f",
            training_run_id, model_version, val_accuracy
        )

        return jsonify({
            'training_run_id': training_run_id,
            'model_version': model_version,
            'metrics': metrics,
            'status': 'completed'
        })

    except Exception as e:
        logger.error("Training failed: %s", type(e).__name__)
        db.execute(
            "UPDATE training_runs SET status = 'failed', completed_at = ? WHERE id = ?",
            (datetime.utcnow().isoformat(), training_run_id)
        )
        db.commit()
        return jsonify({'error': 'Training failed'}), 500


