@app.route('/api/admin/api-keys', methods=['POST'])
@require_auth
@require_role(['admin'])
def create_api_key():
    """Create a new API key for a user."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Invalid request'}), 400

    target_user_id = data.get('user_id', '').strip()
    key_name = data.get('name', '').strip()
    expires_days = data.get('expires_days', 90)

    try:
        uuid.UUID(target_user_id)
    except ValueError:
        return jsonify({'error': 'Invalid user ID'}), 400

    if not re.match(r'^[a-zA-Z0-9_\-\s]{1,100}$', key_name):
        return jsonify({'error': 'Invalid key name'}), 400

    if not isinstance(expires_days, int) or expires_days < 1 or expires_days > 365:
        return jsonify({'error': 'expires_days must be between 1 and 365'}), 400

    # Generate secure API key
    raw_key = secrets.token_urlsafe(48)
    key_hash = hashlib.sha256(raw_key.encode()).hexdigest()
    key_id = str(uuid.uuid4())

    db = get_db()
    db.execute(
        """INSERT INTO api_keys (id, user_id, key_hash, name, is_active, created_at, expires_at)
           VALUES (?, ?, ?, ?, 1, ?, ?)""",
        (
            key_id,
            target_user_id,
            key_hash,
            key_name,
            datetime.utcnow().isoformat(),
            (datetime.utcnow() + timedelta(days=expires_days)).isoformat()
        )
    )
    db.commit()

    logger.info("API key created: key_id=%s, for_user=%s, by=%s", key_id, target_user_id, g.current_user['id'])

    # Return the raw key only once - it cannot be retrieved again
    return jsonify({
        'key_id': key_id,
        'api_key': raw_key,
        'expires_at': (datetime.utcnow() + timedelta(days=expires_days)).isoformat(),
        'warning': 'Store this API key securely. It cannot be retrieved again.'
    }), 201


def create_initial_admin():
    """Create initial admin user if none exists."""
    conn = sqlite3.connect(DATABASE_PATH)
    admin = conn.execute("SELECT id FROM users WHERE role = 'admin'").fetchone()
    if not admin:
        admin_password = os.environ.get('INITIAL_ADMIN_PASSWORD')
        if not admin_password:
            logger.error("No admin exists and INITIAL_ADMIN_PASSWORD not set. Cannot create admin.")
            conn.close()
            return

        admin_id = str(uuid.uuid4())
        password_hash = generate_password_hash(admin_password, method='pbkdf2:sha256:600000')
        conn.execute(
            "INSERT INTO users (id, username, password_hash, role, reputation_score, is_active, created_at) VALUES (?, ?, ?, ?, ?, ?, ?)",
            (admin_id, 'admin', password_hash, 'admin', 1.0, 1, datetime.utcnow().isoformat())
        )
        conn.commit()
        logger.info("Initial admin user created: user_id=%s", admin_id)
    conn.close()


